export const dimensions = [
  {
    key: "EI",
    title: "ენერგიის წყარო (E / I)",
    intro:
      "ზომავს, საიდან იღებთ ენერგიას: ადამიანებთან ურთიერთობიდან (E) თუ განმარტოებით, შინაგანად (I).",
    questions: [
      {
        text:
          "ხანგრძლივი სამუშაო დღის შემდეგ, თქვენთვის ენერგიის აღდგენისა და განტვირთვის საუკეთესო გზაა:",
        a: { text: "ადამიანებთან ურთიერთობა", value: "E" },
        b: { text: "განმარტოება, ფიქრი", value: "I" }
      },
      {
        text: "მნიშვნელოვანი აზრის ჩამოყალიბებისას, სათქმელს:",
        a: { text: "საუბრის პარალელურად ალაგებთ", value: "E" },
        b: { text: "ფიქრის შემდეგ ახმოვანებთ", value: "I" }
      },
      {
        text: "ხანგრძლივი სოციალური აქტივობა თქვენთვის:",
        a: { text: "სტიმულს და მოტივაციას გაძლევთ", value: "E" },
        b: { text: "გღლით", value: "I" }
      },
      {
        text: "ახალი ჯგუფის გაცნობისას საუბარში:",
        a: { text: "ადვილად და მალევე ერთვებით", value: "E" },
        b: { text: "აკვირდებით და ნელ-ნელა ერთვებით", value: "I" }
      },
      {
        text: "განმარტოებით გატარებული ხანგრძლივი დროის შემდეგ:",
        a: { text: "იღლებით და ადამიანებთან კონტაქტი გენატრებათ", value: "E" },
        b: { text: "შინაგან სიმშვიდეს და ენერგიას გრძნობთ", value: "I" }
      },
      {
        text: "პრობლემის გადაჭრისას უფრო ხშირად:",
        a: { text: "პასუხებს დიალოგსა და სხვებთან აზრების გაცვლაში პოულობთ", value: "E" },
        b: { text: "დამოუკიდებლად აანალიზებთ სიტუაციას და ისე მიდიხართ დასკვნამდე", value: "I" }
      },
      {
        text: "თქვენთვის „კარგი დღე“, ძირითადად, ნიშნავს:",
        a: { text: "აქტიურ კომუნიკაციასა და ემოციურად დატვირთულ ურთიერთობებს", value: "E" },
        b: { text: "მშვიდ, კონტროლირებულ და დამოუკიდებლად გატარებულ დროს", value: "I" }
      },
      {
        text: "ემოციური დაძაბულობის ან სტრესის დროს:",
        a: { text: "სხვებთან საუბარი გეხმარებათ სიტუაციის დამუშავებაში", value: "E" },
        b: { text: "პირველ რიგში მარტო რჩებით და შინაგანად აანალიზებთ", value: "I" }
      },
      {
        text: "სოციალური დღის შემდეგ:",
        a: { text: "იშვიათად გჭირდებათ ხანგრძლივი განმარტოება", value: "E" },
        b: { text: "აუცილებელია მარტო ყოფნა ენერგიის სრულად აღსადგენად", value: "I" }
      },
      {
        text: "როდესაც დღის განმავლობაში თავისუფალი დრო მოულოდნელად გიჩნდებათ:",
        a: { text: "ცდილობთ სხვებთან კონტაქტს ან ახალი აქტივობებს", value: "E" },
        b: { text: "იყენებთ პირადი ინტერესებისთვის ან მარტო ყოფნისთვის", value: "I" }
      },
      {
        text: "სხევთან საუბრის გარეშე გატარებული დრო თქვენთვის:",
        a: { text: "მალე ერთფეროვანი და მოსაწყენი ხდება", value: "E" },
        b: { text: "ხშირად კომფორტული და ენერგიის მომცემია", value: "I" }
      },
      {
        text: "მეგობრული ურთიერთობების ჩამოყალიბებისას თქვენთვის უფრო დამახასიათებელია:",
        a: { text: "მარტივად და სწრაფად დაამყაროთ ახალი ნაცნობობა და ნდობა", value: "E" },
        b: { text: "ფრთხილად მიუდგეთ მეგობრების არჩევას და ნდობა მხოლოდ ხანგრძლივი ურთიერთობის შემდეგ ჩამოაყალიბოთ", value: "I" }
      },
      {
        text: "მეგობრულ ურთიერთობებში თქვენთვის უფრო ბუნებრივია:",
        a: { text: "ფართო წრის ყოლა და ხშირი კომუნიკაცია", value: "E" },
        b: { text: "მცირე, შერჩეული წრის შენარჩუნება და ღრმა კავშირები", value: "I" }
      }
    ],
    descriptions: {
      E: "<E - ენერგიას იღებთ ადამიანებთან აქტიური ურთიერთობით.",
      I: "ენერგიას იღებთ განმარტოებით და შინაგანი კონცენტრაციით."
    }
  }
];
